import React, { useState, useEffect } from "react";
import "./UserProfile.css";

function UserProfile() {
    const [profile, setProfile] = useState({
        id: "",
        name: "",
        email: "",
        contact: "",
        license: "",
        nid: "",
        picture: null,
    });

    // load saved profile from localStorage (if any) on mount
    useEffect(() => {
        const saved = localStorage.getItem("userProfile");

        if (saved) {
            try {
                setProfile(JSON.parse(saved));
            } 
            catch (err) {
                console.error("Failed to parse saved profile:", err);
            }
        }
    }, []);

    const handleChange = (e) => {
        const name = e.target.name;

        if (name === "picture") {
            const file = e.target.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onloadend = () => {
                    setProfile((prev) => ({ ...prev, picture: reader.result }));
                };
                reader.readAsDataURL(file);
            }
        } 
        else {
            const value = e.target.value;
            setProfile((prev) => ({ ...prev, [name]: value }));
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        // require all important fields to be filled before save
        const required = ["name", "email", "contact", "license", "nid"];
        for (let i = 0; i < required.length; i++) {
            const key = required[i];
            if (!profile[key] || profile[key].toString().trim() === "") {
                alert("Please fill " + key);
                return;
            }
        }

        // save to localStorage
        try {
            localStorage.setItem("userProfile", JSON.stringify(profile));
            alert("Profile saved locally.");
        } 
        catch (err) {
            console.error("Failed to save profile:", err);
            alert("Failed to save profile locally.");
        }
    };

    return (
        <div className="user-profile-container container-fluid py-4">
            <div className="row gx-4">
                {/* Left Side: Profile Form */}
                <div className="col-lg-6">
                    <div className="card shadow profile-form-card">
                        <div className="card-header bg-primary text-white">
                            <h4>User Profile</h4>
                            <small>Manage your account details</small>
                        </div>

                        <div className="card-body">
                            <form onSubmit={handleSubmit}>
                                {[
                                    { label: "Full Name", name: "name", type: "text" },
                                    { label: "Email Address", name: "email", type: "email" },
                                    { label: "Contact Number", name: "contact", type: "tel" },
                                    { label: "License Number", name: "license", type: "text" },
                                    { label: "NID Number", name: "nid", type: "text" },
                                ].map((field) => (
                                    <div className="mb-3" key={field.name}>
                                        <label className="form-label">{field.label}</label>
                                        <input
                                            type={field.type}
                                            className="form-control"
                                            name={field.name}
                                            value={profile[field.name] || ""}
                                            onChange={handleChange}
                                        />
                                    </div>
                                ))}

                                <div className="mb-4">
                                    <label className="form-label">Upload Picture</label>
                                    <input
                                        type="file"
                                        className="form-control"
                                        name="picture"
                                        accept="image/*"
                                        onChange={handleChange}
                                    />
                                </div>

                                <button className="btn btn-primary w-100" type="submit">
                                    Save Profile
                                </button>
                            </form>
                        </div>
                    </div>
                </div>

                {/* Right Side: Profile Preview */}
                <div className="col-lg-6">
                    <div className="card shadow profile-preview-card">
                        <div className="card-header bg-primary text-white">
                            <h4>Profile Preview</h4>
                            <small>Check how your profile looks</small>
                        </div>

                        <div className="card-body text-center">
                            {profile.picture ? (
                                <img src={profile.picture} alt="Profile" className="profile-image mb-3" />
                            ) : (
                                <div className="profile-placeholder mb-3">
                                    <i className="fas fa-user fa-3x"></i>
                                </div>
                            )}

                            <div className="profile-info">
                                <h5 className="fw-bold mb-2">{profile.name || "Full Name"}</h5>

                                <div className="profile-detail">
                                    <span className="label">📧 Email:</span>
                                    <span className="value">{profile.email || ""}</span>
                                </div>

                                <div className="profile-detail">
                                    <span className="label">📱 Contact:</span>
                                    <span className="value">{profile.contact || ""}</span>
                                </div>

                                <div className="profile-detail">
                                    <span className="label">🚗 License:</span>
                                    <span className="value">{profile.license || "-"}</span>
                                </div>

                                <div className="profile-detail">
                                    <span className="label">🆔 NID:</span>
                                    <span className="value">{profile.nid || "-"}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default UserProfile;
